import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cuda_src = """
#include <torch/extension.h>
#include <cuda_runtime.h>

__global__ void im2col_gemm_conv2d_kernel(
    const float* input, const float* weight, float* output,
    int N, int C_in, int H, int W, int C_out, int K, int H_out, int W_out) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = N * C_out * H_out * W_out;
    if (idx >= total) return;
    int ow = idx % W_out; int oh = (idx / W_out) % H_out;
    int co = (idx / (H_out * W_out)) % C_out; int n = idx / (C_out * H_out * W_out);
    float sum = 0.0f;
    int pad = K / 2;
    for (int ci = 0; ci < C_in; ci++)
        for (int kh = 0; kh < K; kh++)
            for (int kw = 0; kw < K; kw++) {
                int ih = oh + kh - pad, iw = ow + kw - pad;
                if (ih >= 0 && ih < H && iw >= 0 && iw < W)
                    sum += input[((n * C_in + ci) * H + ih) * W + iw]
                         * weight[((co * C_in + ci) * K + kh) * K + kw];
            }
    output[idx] = sum;
}

torch::Tensor conv2d_forward(torch::Tensor input, torch::Tensor weight) {
    int N = input.size(0), C_in = input.size(1), H = input.size(2), W = input.size(3);
    int C_out = weight.size(0), K = weight.size(2);
    int H_out = H, W_out = W;  // same padding
    auto output = torch::empty({N, C_out, H_out, W_out}, input.options());
    int total = N * C_out * H_out * W_out;
    im2col_gemm_conv2d_kernel<<<(total+255)/256, 256>>>(
        input.data_ptr<float>(), weight.data_ptr<float>(), output.data_ptr<float>(),
        N, C_in, H, W, C_out, K, H_out, W_out);
    return output;
}
"""

cpp_src = "torch::Tensor conv2d_forward(torch::Tensor, torch::Tensor);"
conv_mod = load_inline(name='conv2d_cuda', cpp_sources=cpp_src, cuda_sources=cuda_src,
                       functions=['conv2d_forward'])

class ModelNew(nn.Module):
    def __init__(self, in_channels, out_channels, kernel_size):
        super().__init__()
        self.weight = nn.Parameter(torch.randn(out_channels, in_channels, kernel_size, kernel_size))

    def forward(self, x):
        return conv_mod.conv2d_forward(x.contiguous(), self.weight.contiguous())
